SELECT FROM blog_comment c LEFT JOIN blog_article a ON a.id = c.article_id AND a.deleted_at IS NULL WHERE c.deleted_at IS NULL
AND c.article_id = #{articleId}
AND c.status = #{status}
AND ( c.content LIKE CONCAT('%', #{keyword}, '%') OR a.title LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY c.created_at DESC, c.id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(1) FROM blog_comment c LEFT JOIN blog_article a ON a.id = c.article_id AND a.deleted_at IS NULL WHERE c.deleted_at IS NULL
AND c.article_id = #{articleId}
AND c.status = #{status}
AND ( c.content LIKE CONCAT('%', #{keyword}, '%') OR a.title LIKE CONCAT('%', #{keyword}, '%') )

SELECT FROM ( SELECT , ROW_NUMBER() OVER (PARTITION BY root_comment_id ORDER BY created_at ASC, id ASC) AS row_num FROM blog_comment WHERE root_comment_id IN
#{rootCommentId}
AND parent_id IS NOT NULL AND deleted_at IS NULL AND status = 'PUBLISHED' ) preview_rows WHERE row_num <= #{limitPerRoot} ORDER BY root_comment_id ASC, created_at ASC, id ASC

SELECT FROM blog_comment WHERE id IN
#{commentId}
AND deleted_at IS NULL AND status = 'PUBLISHED'

SELECT COUNT(1)
FROM blog_comment
WHERE id = #{id}

SELECT root_comment_id AS rootCommentId, COUNT(1) AS replyCount FROM blog_comment WHERE root_comment_id IN
#{rootCommentId}
AND parent_id IS NOT NULL AND deleted_at IS NULL AND status = 'PUBLISHED' GROUP BY root_comment_id
